def count_distinct_pairs(nums, target):
    counter = {}
    count = 0

    for num in nums:
        if (target - num) in counter:
            count += counter[target - num]
        else:
            counter[num] = nums.count(num) if num not in counter else counter[num] + nums.count(num)

    for key, value in counter.items():
        if key + target == 2 * sum(nums):
            count += value

    return count
